#include <stdio.h>

int calculateMaxProfit(int *price, int n, int fee) {
    if (n == 0) return 0;
    long long cash = 0;
    long long hold = -price[0];
    for (int i = 1; i < n; ++i) {
        long long newCash = cash > (hold + price[i] - fee) ? cash : (hold + price[i] - fee);
        long long newHold = hold > (cash - price[i]) ? hold : (cash - price[i]);
        cash = newCash;
        hold = newHold;
    }
    return (int)cash;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int price[N];
        for (int i = 0; i < N; ++i) scanf("%d", &price[i]);
        int fee; scanf("%d", &fee);
        printf("%d\n", calculateMaxProfit(price, N, fee));
    }
    return 0;
}

