#include <bits/stdc++.h>
using namespace std;

long long calculateMaxProfit(const vector<int>& price, int fee) {
    if (price.empty()) return 0;
    long long cash = 0;
    long long hold = -price[0];
    for (size_t i = 1; i < price.size(); ++i) {
        long long newCash = max(cash, hold + price[i] - fee);
        long long newHold = max(hold, cash - price[i]);
        cash = newCash;
        hold = newHold;
    }
    return cash;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> price(N);
        for (int i = 0; i < N; ++i) cin >> price[i];
        int fee; cin >> fee;
        cout << calculateMaxProfit(price, fee) << '\n';
    }
    return 0;
}

