import java.io.*;
import java.util.*;

public class Main {
    private static long calculateMaxProfit(int[] price, int fee) {
        if (price.length == 0) return 0;
        long cash = 0;
        long hold = -price[0];
        for (int i = 1; i < price.length; i++) {
            long newCash = Math.max(cash, hold + price[i] - fee);
            long newHold = Math.max(hold, cash - price[i]);
            cash = newCash;
            hold = newHold;
        }
        return cash;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] price = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) price[i] = Integer.parseInt(st.nextToken());
            int fee = Integer.parseInt(br.readLine().trim());
            sb.append(calculateMaxProfit(price, fee)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

